# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import base64
import requests
import logging

# Initialize a logger
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Define the header names
# CloudFront event headers are typically lowercased
ENRICH_URL_HEADER_LOWER = 'x-enrich-url'
ENRICHED_DATA_HEADER_LOWER = 'x-enriched-data'
# Original case for setting the 'key' in the header item
ENRICHED_DATA_HEADER_ORIGINAL_CASE = 'X-Enriched-Data'

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    logger.info(f"Viewer request received: {json.dumps(request)}")

    # Check if the enrichment header is present in the request
    if ENRICH_URL_HEADER_LOWER in headers:
        enrich_urls_header_values = headers[ENRICH_URL_HEADER_LOWER]
        enrich_urls_list = []

        # The header value can contain multiple URLs separated by commas
        for header_item in enrich_urls_header_values:
            urls_str = header_item['value']
            # Split by comma and strip whitespace from each URL
            enrich_urls_list.extend([url.strip() for url in urls_str.split(',') if url.strip()])

        logger.info(f"Found enrichment URLs: {enrich_urls_list}")

        enriched_data = {}
        for url in enrich_urls_list:
            try:
                # Make an HTTP GET request with a timeout.
                # A short timeout is crucial for Lambda@Edge performance and cost.
                response = requests.get(url, timeout=2) # 2 seconds timeout per request
                response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)

                # Attempt to parse the response as JSON. If it fails, store as plain text.
                try:
                    data = response.json()
                    logger.info(f"Successfully fetched and parsed JSON from {url}")
                except json.JSONDecodeError:
                    data = response.text
                    logger.info(f"Successfully fetched text from {url}")
                
                # Store the fetched data using the URL as a key.
                # Consider hashing or shortening URLs if they are excessively long.
                enriched_data[url] = data

            except requests.exceptions.Timeout:
                logger.error(f"Timeout fetching data from {url}")
                enriched_data[url] = {"error": "Timeout fetching data"}
            except requests.exceptions.RequestException as e:
                logger.error(f"Error fetching data from {url}: {e}")
                enriched_data[url] = {"error": f"Request failed: {str(e)}"}
            except Exception as e:
                logger.error(f"An unexpected error occurred while processing {url}: {e}")
                enriched_data[url] = {"error": f"Unexpected error: {str(e)}"}
        
        # If any data was successfully enriched, add it to a new header
        if enriched_data:
            # Convert the dictionary of enriched data to a JSON string
            enriched_data_json_str = json.dumps(enriched_data)
            
            # Base64 encode the JSON string to ensure it's safe for HTTP headers
            # and to handle any special characters. UTF-8 encoding is good practice.
            encoded_data = base64.b64encode(enriched_data_json_str.encode('utf-8')).decode('ascii')
            
            # Add the new custom header to the request.
            # CloudFront expects the dictionary key for headers to be lowercase,
            # but the 'key' field within the header item should be the original case.
            headers[ENRICHED_DATA_HEADER_LOWER] = [{
                'key': ENRICHED_DATA_HEADER_ORIGINAL_CASE,
                'value': encoded_data
            }]
            logger.info(f"Added {ENRICHED_DATA_HEADER_ORIGINAL_CASE} header with encoded data.")
        else:
            logger.info("No data was successfully enriched from the provided URLs.")
    else:
        logger.info(f"No {ENRICH_URL_HEADER_LOWER} header found in the request. Skipping enrichment.")

    # Return the modified request object
    return request